class AuditEvent {
  final String id;
  final DateTime occurredAt;
  final String action;

  AuditEvent({
    required this.id,
    required this.occurredAt,
    required this.action,
  }) {
    if (id.isEmpty) {
      throw ArgumentError.value(id, 'id', 'must not be empty');
    }
    if (!occurredAt.isUtc) {
      throw ArgumentError.value(occurredAt, 'occurredAt', 'must be UTC');
    }
  }
}

