import 'dart:math';

import 'audit_event.dart';
import 'audit_order.dart';

class AuditPage {
  final List<AuditEvent> events;
  final String? nextCursor;

  AuditPage(Iterable<AuditEvent> events, this.nextCursor)
    : events = List<AuditEvent>.unmodifiable(events);
}

class AuditPager {
  AuditPage page(
    Iterable<AuditEvent> events, {
    required int limit,
    String? after,
  }) {
    if (limit <= 0) {
      throw ArgumentError.value(limit, 'limit', 'must be positive');
    }

    final ordered = List<AuditEvent>.of(events)..sort(compareAuditEvents);
    var start = 0;
    if (after != null) {
      final boundary = DateTime.parse(after);
      start = ordered.indexWhere(
        (event) => event.occurredAt.isBefore(boundary),
      );
      if (start < 0) {
        return AuditPage(const <AuditEvent>[], null);
      }
    }

    final end = min(start + limit, ordered.length);
    final selected = ordered.sublist(start, end);
    final nextCursor = end < ordered.length
        ? selected.last.occurredAt.toIso8601String()
        : null;
    return AuditPage(selected, nextCursor);
  }
}

