import '../lib/audit_event.dart';
import '../lib/audit_order.dart';
import '../lib/audit_pager.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

AuditEvent event(String id, int minute) {
  return AuditEvent(
    id: id,
    occurredAt: DateTime.utc(2026, 4, 20, 12, minute),
    action: 'viewed',
  );
}

void main() {
  check(
    compareAuditEvents(event('newer', 3), event('older', 2)) < 0,
    'newer events sort first',
  );

  final events = <AuditEvent>[
    event('evt-a', 1),
    event('evt-c', 3),
    event('evt-b', 2),
  ];
  final pager = AuditPager();
  final first = pager.page(events, limit: 2);
  check(
    first.events.map((event) => event.id).join(',') == 'evt-c,evt-b',
    'returns the first page in event-time order',
  );
  check(first.nextCursor != null, 'provides a cursor when records remain');

  final second = pager.page(events, limit: 2, after: first.nextCursor);
  check(
    second.events.map((event) => event.id).join(',') == 'evt-a',
    'continues after a distinct event time',
  );
  check(second.nextCursor == null, 'ends the cursor chain at the last page');

  print('public tests passed');
}
